import type * as React from 'react';

import {cn} from '@/lib/utils';

import {ScrollArea as ScrollAreaPrimitive} from 'radix-ui';

/**
 * Augments native scroll functionality for custom, cross-browser styling.
 *
 * ### Component Props
 *
 * See [Scroll Area props](https://www.radix-ui.com/primitives/docs/components/scroll-area) documentation for full details.
 *
 * | Prop               | Type                                        | Default  |
 * | :----------------- | :------------------------------------------ | :------- |
 * | _asChild_          | `boolean`                                   | `false`  |
 * | _type_             | `"auto" \| "always" \| "scroll" \| "hover"` | `"hover"` |
 * | _scrollHideDelay_  | `number`                                    | `600`    |
 * | _dir_              | `"ltr" \| "rtl"`                            | -        |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <ScrollArea className="h-72 w-48 rounded-md border">
 *   <div className="p-4">
 *     <h4>Content</h4>
 *     <p>Scrollable content goes here...</p>
 *   </div>
 * </ScrollArea>
 * ```
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 2.1.1 Keyboard — viewport is focusable and scrollable via keyboard; focus ring via `focus-visible:ring-3`.
 */
function ScrollArea({
  className,
  children,
  ...props
}: React.ComponentProps<typeof ScrollAreaPrimitive.Root>) {
  return (
    <ScrollAreaPrimitive.Root
      data-slot="scroll-area"
      className={cn('relative', className)}
      {...props}
    >
      <ScrollAreaPrimitive.Viewport
        data-slot="scroll-area-viewport"
        tabIndex={0}
        className="size-full rounded-[inherit] transition-[color,box-shadow] ease-default outline-none focus-visible:ring-3 focus-visible:ring-ring focus-visible:outline-1"
      >
        {children}
      </ScrollAreaPrimitive.Viewport>
      <ScrollBar />
      <ScrollAreaPrimitive.Corner />
    </ScrollAreaPrimitive.Root>
  );
}

/**
 * A scrollbar element within a ScrollArea for scrolling content along an axis.
 *
 * ### Component Props
 *
 * See [Scroll Area Scrollbar props](https://www.radix-ui.com/primitives/docs/components/scroll-area) documentation for full details.
 *
 * | Prop           | Type                           | Default      |
 * | :------------- | :----------------------------- | :----------- |
 * | _asChild_      | `boolean`                      | `false`      |
 * | _forceMount_   | `boolean`                      | -            |
 * | _orientation_  | `"vertical" \| "horizontal"`   | `"vertical"` |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <ScrollArea>
 *   <div>Content</div>
 *   <ScrollBar orientation="horizontal" />
 * </ScrollArea>
 * ```
 */
function ScrollBar({
  className,
  orientation = 'vertical',
  ...props
}: React.ComponentProps<typeof ScrollAreaPrimitive.ScrollAreaScrollbar>) {
  return (
    <ScrollAreaPrimitive.ScrollAreaScrollbar
      data-slot="scroll-area-scrollbar"
      data-orientation={orientation}
      orientation={orientation}
      className={cn(
        'flex touch-none p-px transition-colors ease-default select-none data-horizontal:h-2.5 data-horizontal:flex-col data-horizontal:border-t data-horizontal:border-t-transparent data-vertical:h-full data-vertical:w-2.5 data-vertical:border-l data-vertical:border-l-transparent',
        className
      )}
      {...props}
    >
      <ScrollAreaPrimitive.ScrollAreaThumb
        data-slot="scroll-area-thumb"
        className="relative flex-1 rounded-full bg-border"
      />
    </ScrollAreaPrimitive.ScrollAreaScrollbar>
  );
}

export {ScrollArea, ScrollBar};
